# Create an AppFlow flow that pulls Salesforce contacts into S3 daily
aws appflow create-flow \
  --flow-name salesforce-contacts-to-s3 \
  --source-flow-config "{
    \"connectorType\": \"Salesforce\",
    \"connectorProfileName\": \"my-salesforce-connection\",
    \"sourceConnectorProperties\": {
      \"Salesforce\": {
        \"object\": \"Contact\",
        \"enableDynamicFieldUpdate\": false,
        \"includeDeletedRecords\": false
      }
    }
  }" \
  --destination-flow-config-list "[{
    \"connectorType\": \"S3\",
    \"destinationConnectorProperties\": {
      \"S3\": {
        \"bucketName\": \"my-crm-data-lake\",
        \"bucketPrefix\": \"salesforce/contacts/\",
        \"s3OutputFormatConfig\": {
          \"fileType\": \"PARQUET\"
        }
      }
    }
  }]" \
  --trigger-config "{
    \"triggerType\": \"Scheduled\",
    \"triggerProperties\": {
      \"Scheduled\": {
        \"scheduleExpression\": \"rate(1day)\",
        \"dataPullMode\": \"Incremental\"
      }
    }
  }"
